#include<bits/stdc++.h>
using namespace std;
const int LEN = 1e6+5;
string s;
int len,l1[LEN],l2[LEN],c1[LEN],c2[LEN];
int sum,sc1,sc2;
void init(){
    len=s.size();
    s=' '+s;
    int x=0;//用来记录括号层数
    for(int i=1;i<=len;i++){
        if(s[i]=='(')x++;
        else if(s[i]==')')x--;
        else if(s[i]=='|')l1[x]=i;
        else if(s[i]=='&')l2[x]=i;
        else;
        c1[i]=l1[x];
        c2[i]=l2[x];
    }
}
int DFS(int l,int r){
    if(c1[r]>=l){
        int as=DFS(l,c1[r]-1);//算左边
        if(as==1){//触发短路
            sc1++;
            return 1;
        }
        return (as|DFS(c1[r]+1,r));
    }
    if(c2[r]>=l){
        int as=DFS(l,c2[r]-1);//算左边
        if(as==0){//触发短路
            sc2++;
            return 0;
        }
        return (as&DFS(c2[r]+1,r));
    }
    if(s[l]=='('&&s[r]==')')
        return DFS(l+1,r-1);//去掉最外围的括号
    return s[l]-'0';
}
int main(){
    cin>>s;
    init();
    sum=DFS(1,len);
    cout<<sum<<"\n"<<sc2<<" "<<sc1;
    return 0;
}
